"use client";
import React from "react";
import { Plus } from "lucide-react";

interface Props {
 id: number;
 name: string;
 weight: string;
 price: number;
 oldPrice?: number;
 discount?: string;
 image: string;
 onAdd: () => void;
}

const ProductCard: React.FC<Props> = ({ name, weight, price, oldPrice, discount, image, onAdd }) => (
 <div
  className="group relative flex flex-col bg-white p-7 transition-all duration-700 ease-premium cursor-pointer rounded-[2.5rem] hover:-translate-y-3 hover:shadow-wow-hover shadow-subtle border border-black/[0.03]"
 >
  {/* ── Status Label ── */}
  <div className="absolute top-8 left-8 z-20 flex items-center gap-1.5 rounded-full bg-white/95 backdrop-blur-sm px-3 py-1 text-[11px] font-[900] tracking-tight text-meren-black shadow-sm border border-black/5 uppercase font-manrope scale-110 origin-left">
   <div className="h-1.5 w-1.5 rounded-full bg-meren-black animate-pulse" />
   {discount || "новинка"}
  </div>

  {/* ── Clean Hero Image ── */}
  <div className="relative mb-8 flex aspect-square items-center justify-center overflow-hidden rounded-[2rem] bg-[#F5F5F7] transition-colors duration-700 group-hover:bg-[#EBEBF0]">
   <img
    src={image}
    alt={name}
    loading="lazy"
    className="h-[82%] w-[82%] object-contain mix-blend-multiply transition-transform duration-1000 ease-premium group-hover:scale-115"
   />

   {/* ── Large Premium Add Button ── */}
   <button
    onClick={(e) => { e.stopPropagation(); onAdd(); }}
    className="absolute bottom-6 right-6 flex h-14 w-14 items-center justify-center rounded-full bg-meren-black text-white shadow-wow opacity-0 translate-y-6 transition-all duration-700 ease-premium group-hover:opacity-100 group-hover:translate-y-0 hover:scale-110 active:scale-90"
   >
    <Plus className="w-7 h-7" strokeWidth={3} />
   </button>
  </div>

  {/* ── Minimalist Info (Coffee Grid Style) ── */}
  <div className="flex flex-col font-manrope px-2">
   <div className="flex items-center justify-between mb-3">
    <p className="text-[20px] font-[1000] leading-tight text-meren-black tracking-[-0.04em] line-clamp-1">
     {name}
    </p>
   </div>

   <div className="flex items-end justify-between mt-auto">
    <div className="flex flex-col">
     <div className="flex items-baseline gap-1.5">
      <p className="text-[20px] font-[1000] text-meren-black tracking-tighter leading-none">
       {price}
      </p>
      <span className="text-[14px] font-black text-meren-black/20 uppercase tracking-widest">₽</span>
     </div>
     {oldPrice && (
      <p className="text-[13px] font-bold text-meren-gray line-through leading-none mt-1 opacity-50">
       {oldPrice} ₽
      </p>
     )}
    </div>
    <div className="flex flex-col items-end">
     <p className="text-[12px] font-black text-meren-gray uppercase tracking-widest opacity-60">
      {weight}
     </p>
    </div>
   </div>
  </div>
 </div>
);

export default ProductCard;
